 52→export function nextSectionLabel(existingCuts = []) {
 53→  const usedLetters = new Set(
 54→    existingCuts
 55→      .map(c => {
 56→        const match = c.label?.match(/^Section\s+([A-Z])-\1$/);
 57→        return match ? match[1] : null;
 58→      })
 59→      .filter(Boolean)
 60→  );
 61→  for (let i = 0; i < 26; i++) {
 62→    const letter = String.fromCharCode(65 + i);
 63→    if (!usedLetters.has(letter)) return `Section ${letter}-${letter}`;
 64→  }
 65→  return `Section ${existingCuts.length + 1}`;
 66→}
