116→function AppInner() {
117→  const { project, isDirty, dispatch } = useProject();
118→  const orderedFloors = useMemo(() => getOrderedFloors(project), [project]);
119→  const availableFloorIds = useMemo(() => orderedFloors.map((floor) => floor.id), [orderedFloors]);
120→  const availablePhaseIds = useMemo(() => (project.phases || []).map((p) => p.id), [project.phases]);
121→  const initialActiveFloorId = getDefaultActiveFloorId(project);
122→  const [showLoadModal, setShowLoadModal] = useState(false);
123→  const [savedProjects, setSavedProjects] = useState([]);
124→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
125→  const [isPropertiesCollapsed, setIsPropertiesCollapsed] = useState(false);
126→  const [projectFileHandle, setProjectFileHandle] = useState(null);
127→  const importInputRef = useRef(null);
128→
129→  useAutosave(project, isDirty, dispatch);
130→
131→  // beforeunload warning
132→  useEffect(() => {
133→    const handler = (e) => {
134→      if (isDirty) {
135→        e.preventDefault();
136→        e.returnValue = '';
137→      }
138→    };
139→    window.addEventListener('beforeunload', handler);
140→    return () => window.removeEventListener('beforeunload', handler);
141→  }, [isDirty]);
142→
143→  const handleNew = useCallback(() => {
144→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
145→    setProjectFileHandle(null);
146→    dispatch({ type: 'PROJECT_NEW', project: createProject() });
147→  }, [isDirty, dispatch]);
148→
149→  const handleSave = useCallback(async () => {
150→    try {
151→      const { fileHandle } = await exportProjectFile(project, { fileHandle: projectFileHandle });
152→      setProjectFileHandle(fileHandle);
153→      try {
154→        await saveProject(project);
155→      } catch {
156→        // Browser draft sync is secondary to file save.
157→      }
158→      dispatch({ type: 'MARK_SAVED' });
159→    } catch (err) {
160→      if (isFilePickerAbortError(err)) return;
161→      alert('Failed to save project file: ' + err.message);
162→    }
163→  }, [project, projectFileHandle, dispatch]);
164→
165→  // Ctrl+S save
166→  useEffect(() => {
167→    const handler = (e) => {
168→      if (isTypingTarget(e.target)) return;
169→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
170→        e.preventDefault();
171→        handleSave();
172→      }
173→    };
174→    window.addEventListener('keydown', handler);
175→    return () => window.removeEventListener('keydown', handler);
176→  }, [handleSave]);
177→
178→  const handleLoadClick = useCallback(async () => {
179→    setSavedProjects(await listProjects());
180→    setShowLoadModal(true);
181→  }, []);
182→
183→  const handleOpenProjectFile = useCallback(async () => {
184→    if (typeof window.showOpenFilePicker !== 'function') {
185→      importInputRef.current?.click();
186→      return;
187→    }
188→
189→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) {
190→      return;
191→    }
192→
193→    try {
194→      const { project: loaded, savedAt, fileHandle } = await openProjectFile();
195→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
196→      setProjectFileHandle(fileHandle);
197→      setShowLoadModal(false);
198→    } catch (err) {
199→      if (isFilePickerAbortError(err)) return;
200→      alert('Failed to import project file: ' + err.message);
201→    }
202→  }, [isDirty, dispatch]);
203→
204→  const handleImportFile = useCallback(async (e) => {
205→    const file = e.target.files?.[0] || null;
206→    e.target.value = '';
207→    if (!file) return;
208→
209→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) {
210→      return;
211→    }
212→
213→    try {
214→      const { project: loaded, savedAt } = await importProjectFile(file);
215→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
216→      setProjectFileHandle(null);
217→      setShowLoadModal(false);
218→    } catch (err) {
219→      alert('Failed to import project file: ' + err.message);
220→    }
221→  }, [isDirty, dispatch]);
222→
223→  const handleLoad = useCallback(async (id) => {
224→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
225→    try {
226→      const { project: loaded, savedAt } = await loadProject(id);
227→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
228→      setProjectFileHandle(null);
229→      setShowLoadModal(false);
230→    } catch (err) {
231→      alert('Failed to load project: ' + err.message);
232→    }
233→  }, [isDirty, dispatch]);
234→
235→  const handleDelete = useCallback(async (id, name) => {
236→    const confirmed = window.confirm(`Delete "${name}"? This cannot be undone.`);
237→    if (!confirmed) return;
238→
239→    try {
240→      await deleteProject(id);
241→      setSavedProjects(projects => projects.filter(project => project.id !== id));
242→    } catch (err) {
243→      alert('Failed to delete project: ' + err.message);
244→    }
245→  }, []);
246→
247→  return (
248→    <EditorProvider
249→      initialActiveFloorId={initialActiveFloorId}
250→      availableFloorIds={availableFloorIds}
251→      availablePhaseIds={availablePhaseIds}
252→    >
253→      <input
254→        ref={importInputRef}
255→        type="file"
256→        accept=".json,application/json"
257→        onChange={handleImportFile}
258→        style={{ display: 'none' }}
259→      />
260→
261→      <EditorShell
262→        project={project}
263→        handleNew={handleNew}
264→        handleSave={handleSave}
265→        handleLoadClick={handleLoadClick}
266→        isSidebarCollapsed={isSidebarCollapsed}
267→        isPropertiesCollapsed={isPropertiesCollapsed}
268→        onToggleSidebar={() => setIsSidebarCollapsed(value => !value)}
269→        onToggleProperties={() => setIsPropertiesCollapsed(value => !value)}
270→      />
271→
272→      {showLoadModal && (
273→        <Modal title="Open Project" onClose={() => setShowLoadModal(false)}>
274→          <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
275→            <div className={modalStyles.modalCard}>
276→              <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
277→                <span className={modalStyles.modalCardTitle}>Project File</span>
278→                <span className={modalStyles.modalCardDesc}>
279→                  Open a JSON file previously saved to your computer.
280→                </span>
281→              </div>
282→              <button className={modalStyles.modalBtn} onClick={handleOpenProjectFile} style={{ alignSelf: 'flex-start' }}>
283→                Open Project File
284→              </button>
285→            </div>
286→
287→            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
288→              <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
289→                <span className={modalStyles.modalCardTitle}>Browser Drafts</span>
290→                <span className={modalStyles.modalCardDesc} style={{ fontSize: '11px' }}>
291→                  Stored only in this browser on this machine.
292→                </span>
293→              </div>
294→              {savedProjects.length === 0 ? (
295→                <p style={{ color: 'var(--color-text-secondary)', fontSize: '13px', margin: 0 }}>
296→                  No browser drafts found.
297→                </p>
298→              ) : (
299→                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
300→                  {savedProjects.map(p => (
301→                    <div key={p.id} className={modalStyles.modalCard} style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' }}>
302→                      <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
303→                        <span style={{ fontWeight: 500, fontSize: '13px' }}>{p.name}</span>
304→                        <span style={{ color: 'var(--color-text-secondary)', fontSize: '11px' }}>
305→                          {new Date(p.savedAt).toLocaleDateString()}
306→                        </span>
307→                      </div>
308→                      <div style={{ display: 'flex', gap: '8px' }}>
309→                        <button className={modalStyles.modalBtn} onClick={() => handleLoad(p.id)}>Load</button>
310→                        <button className={modalStyles.modalBtnDanger} onClick={() => handleDelete(p.id, p.name)}>Delete</button>
311→                      </div>
312→                    </div>
313→                  ))}
314→                </div>
315→              )}
316→            </div>
317→          </div>
318→          <button className={modalStyles.modalBtn} onClick={() => setShowLoadModal(false)} style={{ marginTop: '16px' }}>
319→            Cancel
320→          </button>
321→        </Modal>
322→      )}
323→    </EditorProvider>
324→  );
325→}
326→
327→export default function App() {
328→  return (
329→    <ProjectProvider>
330→      <ClipboardProvider>
331→        <AppInner />
332→      </ClipboardProvider>
333→    </ProjectProvider>
334→  );
335→}
